import React from 'react';

function Nav() {
  const categories = [
    {
      name: 'commercial',
      description: 
        'Photos of grocery stores, food drunks, and other commercial projects',
    },
    {
      name: 'portraits',
      description: 'Portraits of people in my life'
    },
    {
      name: 'food',
      description: 'Delicious delicacies'
    },
    {
      name: 'landscape',
      description: 'Fields, farmhouses, waterfalls, and the beauty of nature',
    },
  ];
  return (
    <header>
      <h2>
        <a href='/'>
          <span role='img' aria-label='camera'>📸</span> Oh Snap!
        </a>
      </h2>
      <nav>
        <ul className='flex-row'>
          <li className='mx-2'>
            <a href='#about'>
              About me
            </a>
          </li>
          <li>
            <span>Contact</span>
          </li>
          {categories.map((category) => (
            <li className='mx-1' key={category.name}>
              <span onClick>
                {category.name}
              </span>
            </li>
          ))}
        </ul>
      </nav>
    </header>
  );
}

export default Nav;
